/* Reasoning GP — Articles data (batch 5: B topics)
   RCGP/SCA examiner depth. NICE NG12 (May 2025) 2WW pathways stated explicitly where relevant. */
(function(){
  const A = (window.RGP_ARTICLES = window.RGP_ARTICLES || []);
  A.push(

  { id:'bakers-cyst', title:'Baker’s cyst (popliteal cyst)', category:'Musculoskeletal', icon:'🦵',
    overview:'A fluid-filled swelling in the popliteal fossa, usually a distension of the gastrocnemius-semimembranosus bursa communicating with the knee joint. In adults it is typically secondary to intra-articular pathology (osteoarthritis, meniscal tear, inflammatory arthritis). The key not-to-miss is a rupture mimicking DVT.',
    features:[
      'Smooth, fluctuant swelling behind the knee, most prominent on standing/extension and softening on flexion (Foucher’s sign)',
      'Often asymptomatic or causes posterior knee tightness/ache; may limit full flexion',
      'In adults almost always secondary — look for the underlying knee disorder (OA, meniscal tear, RA, gout)',
      'In children it is usually primary and benign, requiring only reassurance',
      'RUPTURE mimics DVT: sudden calf pain, swelling and bruising (a "crescent sign" around the ankle) — examine and exclude true DVT',
      'Diagnosis is clinical; ultrasound confirms and distinguishes from DVT, popliteal aneurysm and (rarely) tumour'],
    management:[
      'Confirm the diagnosis clinically; arrange ultrasound if uncertain or to exclude DVT/aneurysm',
      'Treat the underlying knee pathology — that is what resolves most adult cysts',
      'Conservative care: reassurance, simple analgesia/NSAIDs, activity modification, and quadriceps/knee rehabilitation',
      'An ultrasound-guided aspiration ± corticosteroid injection can be offered for a large symptomatic cyst',
      'Refer to MSK/orthopaedics for the underlying joint problem (e.g. meniscal tear) rather than the cyst alone',
      'Advise on the rupture presentation and to seek review for sudden calf pain/swelling',
      'Do not aspirate blindly without considering a popliteal aneurysm (pulsatile) — image first if any doubt',
      'Reassure that most cysts are benign and many settle once the joint is treated'],
    referral:[
      'Suspected DVT (acute calf pain/swelling) → assess Wells score and arrange D-dimer/ultrasound per the DVT pathway',
      'Pulsatile popliteal swelling (possible popliteal aneurysm) → urgent vascular assessment',
      'Atypical, rapidly enlarging, or solid swelling → imaging ± soft-tissue sarcoma pathway (NICE NG12 — unexplained enlarging soft-tissue mass → urgent USS/referral)',
      'Persistent symptomatic cyst or significant underlying joint disease → orthopaedics/MSK'],
    source:'NICE CKS — Baker’s cyst' },

  { id:'bartholin-cyst', title:'Bartholin’s cyst and abscess', category:'Women’s health', icon:'🌸',
    overview:'Obstruction of a Bartholin’s gland duct produces a cyst; secondary infection produces a painful abscess. Common in women of reproductive age, usually benign, but a solid or persistent Bartholin’s mass in a woman over 40 raises the (rare) possibility of vulval/Bartholin carcinoma.',
    features:[
      'A unilateral, painless soft swelling at the posterior introitus (4 or 8 o’clock position) when an uninfected cyst',
      'An abscess is acutely painful, red, hot and tender, with difficulty sitting/walking and sometimes fever',
      'May be associated with gonorrhoea/chlamydia — consider an STI screen, particularly with recurrent abscesses',
      'Often fluctuant; surrounding cellulitis may be present in an abscess',
      'RED FLAG: a hard, irregular, fixed or persistent Bartholin mass in a woman >40 — exclude vulval/Bartholin gland carcinoma',
      'Diagnosis is clinical; swab any discharge for culture and STI testing'],
    management:[
      'Asymptomatic small cyst → reassurance, warm baths; no intervention needed',
      'Abscess → analgesia, warm compresses/sitz baths; many point and drain spontaneously',
      'Definitive treatment of an abscess/symptomatic cyst is incision and drainage with a Word catheter or marsupialisation to maintain drainage and reduce recurrence',
      'Antibiotics are not needed for a simple drained abscess unless there is surrounding cellulitis, systemic upset, pregnancy, immunosuppression or suspected STI — then cover accordingly',
      'Take swabs (including for gonorrhoea/chlamydia) and arrange partner notification if an STI is found',
      'Recurrent disease may need marsupialisation or, occasionally, gland excision',
      'Provide self-care advice (warm baths) and safety-net for spreading infection or systemic illness',
      'Biopsy any solid or atypical lesion, and have a low threshold for referral in older women'],
    referral:[
      'Solid, fixed, irregular or persistent Bartholin mass, especially in a woman >40 → 2WW gynae-oncology referral to exclude vulval/Bartholin carcinoma (NICE NG12 — unexplained vulval lump/ulceration)',
      'Large or recurrent abscess/cyst needing definitive surgery → gynaecology',
      'Systemic sepsis or extensive cellulitis → urgent assessment',
      'Confirmed STI → GUM for treatment and partner notification'],
    source:'NICE CKS / NICE NG12' },

  { id:'bedbugs', title:'Bedbugs', category:'Dermatology', icon:'🐛',
    overview:'Bites from Cimex lectularius — small nocturnal insects living in mattresses, furniture and crevices. They cause itchy bites but do not transmit disease. Management is reassurance, symptom relief and, crucially, environmental eradication, since the skin will keep flaring until the infestation is cleared.',
    features:[
      'Itchy erythematous papules, often in clusters or a linear "breakfast-lunch-dinner" pattern, on exposed skin (face, neck, arms, hands)',
      'Bites typically appear in the morning after overnight feeding; reactions range from none to large urticarial wheals or bullae',
      'Clues to infestation: small blood spots or dark faecal marks on bedding, a musty odour, and live bugs in mattress seams/crevices',
      'Recent travel, second-hand furniture or hotel stays are common contexts',
      'Differential: scabies (web spaces, burrows, household itch), flea bites (lower legs), papular urticaria, other insect bites',
      'Secondary bacterial infection can follow scratching'],
    management:[
      'Reassure: bites are self-limiting and bedbugs do not spread infection',
      'Symptom relief: emollients, a topical corticosteroid for itch/inflammation, and an oral antihistamine if needed',
      'Treat secondary bacterial infection with antibiotics if present',
      'Eradication is the key step: thorough cleaning, hot-washing (≥60°C) and high-heat drying of bedding/clothing, vacuuming, and professional pest control for established infestations',
      'Advise on avoiding spread (e.g. when travelling — inspect luggage/furniture)',
      'Explain that skin lesions will continue until the source is eliminated',
      'Avoid unnecessary insecticide use on skin; treat the environment, not the person',
      'Signpost local authority/environmental-health resources where relevant'],
    referral:[
      'Diagnostic uncertainty or atypical widespread rash → dermatology',
      'Severe or extensive bullous reactions → dermatology',
      'Persistent infestation despite measures → professional pest control / environmental health'],
    source:'NICE CKS — Insect bites and stings' },

  { id:'behcets', title:'Behçet’s disease', category:'Allergy & immunology', icon:'🔴',
    overview:'A rare, chronic, relapsing systemic vasculitis affecting vessels of all sizes, classically with recurrent oral and genital ulceration plus uveitis. It can also cause skin, joint, vascular, GI and neurological disease. The sight- and life-threatening complications (uveitis, vascular and neuro-Behçet’s) make recognition important.',
    features:[
      'Recurrent painful oral aphthous ulcers (≥3 times/year) — the hallmark and usually the first feature',
      'Recurrent genital ulcers (often scarring), and ocular disease — anterior/posterior uveitis or retinal vasculitis (sight-threatening)',
      'Skin: erythema nodosum, papulopustular/acneiform lesions; pathergy (a pustule forming at a needle-prick site)',
      'Other systems: arthritis, venous/arterial thrombosis and aneurysm (vascular Behçet’s), GI ulceration, and neuro-Behçet’s (brainstem/meningoencephalitis)',
      'Onset typically 20s–30s; more common and more severe in people from "Silk Road" populations (Turkey, Middle East, East Asia)',
      'No single diagnostic test — diagnosis is clinical using international criteria; investigations exclude mimics and assess organ involvement'],
    management:[
      'Recognise the pattern (recurrent oral + genital ulcers ± eye disease) and refer for specialist diagnosis',
      'Management is specialist and multidisciplinary (rheumatology ± ophthalmology, neurology, gastroenterology), tailored to the organs involved',
      'Mucocutaneous disease: topical corticosteroids for ulcers, colchicine, and topical anaesthetics; systemic agents for resistant disease',
      'Major organ involvement (eye, vascular, neuro, GI): systemic corticosteroids plus immunosuppression (azathioprine, ciclosporin), and biologics (e.g. anti-TNF, interferon) under specialists',
      'Any visual symptom needs same-day ophthalmology — uveitis can rapidly threaten sight',
      'Primary care: support adherence, monitor immunosuppression, manage flares and comorbidity, and provide patient information',
      'Address venous thromboembolism risk and coordinate care across specialties',
      'Provide psychological support — recurrent painful ulceration and uncertainty are debilitating'],
    referral:[
      'Suspected Behçet’s (recurrent oral + genital ulcers ± eye/skin/systemic features) → rheumatology / specialist Behçet’s centre',
      'Any eye symptom (pain, redness, blurring, floaters) → same-day ophthalmology (uveitis)',
      'Neurological features (severe headache, focal deficit, confusion) or vascular events → urgent specialist/emergency assessment',
      'Severe oral/genital ulceration affecting nutrition/function → specialist input'],
    source:'NICE CKS / specialist Behçet’s guidance' },

  { id:'benign-brain-tumours', title:'Non-cancerous (benign) brain tumours', category:'Neurology', icon:'🧠',
    aka:'Benign brain tumours',
    overview:'Slow-growing intracranial tumours (e.g. meningioma, pituitary adenoma, acoustic neuroma) that are non-malignant but can still cause serious harm by compressing or raising pressure within the fixed skull. Many are found incidentally; the primary-care role is recognising the symptom patterns that warrant urgent brain imaging.',
    features:[
      'Progressive headache — classically worse in the morning, on lying down, or with coughing/straining; new or changed pattern in an adult',
      'Features of raised intracranial pressure: headache with nausea/vomiting, visual obscurations, papilloedema, and drowsiness',
      'Focal deficits depending on site: limb weakness/sensory change, dysphasia, visual field loss, unsteadiness',
      'New-onset seizures in an adult, or a first seizure, should prompt imaging',
      'Personality/cognitive change (frontal tumours), endocrine disturbance (pituitary), or unilateral hearing loss (acoustic neuroma)',
      'Diagnosis is by brain imaging (MRI preferred; CT if MRI unavailable/contraindicated)'],
    management:[
      'Recognise the warning patterns and arrange brain imaging promptly — do not attribute progressive or postural headache, new focal deficit, or first adult seizure to benign causes without imaging',
      'Examine for papilloedema, focal neurology and visual fields',
      'Management is specialist and depends on type, size, site and symptoms',
      'Watchful waiting with serial imaging is appropriate for small, asymptomatic incidental meningiomas',
      'Active treatment: neurosurgical resection, stereotactic radiosurgery/radiotherapy, or medical therapy (e.g. dopamine agonists for prolactinomas)',
      'Treat symptoms in primary care under specialist guidance: seizures (anti-seizure medication, with DVLA advice), headache, and endocrine replacement for pituitary lesions',
      'Address driving (advise the patient to notify the DVLA after a seizure or relevant diagnosis) and provide written information',
      'Support patients and families and coordinate neuro-rehabilitation as needed'],
    referral:[
      'Progressive, sub-acute loss of central neurological function in an adult → urgent direct-access MRI brain (or CT) within 2 weeks for suspected brain/CNS tumour (NICE NG12)',
      'Child/young person with newly abnormal cerebellar or other central neurological function → very urgent referral (within 48 hours) (NICE NG12)',
      'Features of raised ICP, rapid deterioration, or new focal deficit/seizure with red flags → emergency assessment',
      'Confirmed tumour → neurosurgery / neuro-oncology MDT'],
    source:'NICE NG12 / NICE CKS — Brain tumour' },

  { id:'schistosomiasis', title:'Schistosomiasis (bilharzia)', category:'Infectious diseases', icon:'🪱',
    aka:'Bilharzia',
    overview:'A parasitic trematode (fluke) infection acquired through freshwater contact in endemic regions (sub-Saharan Africa especially). It ranges from an acute hypersensitivity illness to chronic urinary or intestinal disease. Long-standing urinary schistosomiasis is a recognised cause of bladder squamous-cell carcinoma.',
    features:[
      'Exposure history: swimming/wading in freshwater lakes or rivers in endemic areas (e.g. Lake Malawi)',
      '"Swimmer’s itch": a transient itchy papular rash at the site of cercarial penetration',
      'Acute schistosomiasis (Katayama syndrome): fever, urticaria, myalgia, cough and eosinophilia weeks after exposure',
      'Chronic urinary (S. haematobium): terminal haematuria, dysuria, and — over years — bladder fibrosis, obstructive uropathy and bladder cancer risk',
      'Chronic intestinal/hepatic (S. mansoni/japonicum): abdominal pain, bloody diarrhoea, hepatosplenomegaly and portal hypertension',
      'Diagnosis: eosinophilia, serology, and ova in urine (haematobium) or stool (mansoni); imaging/cystoscopy for complications'],
    management:[
      'Take a travel and freshwater-exposure history in returning travellers with haematuria, eosinophilia or unexplained GI/urinary symptoms',
      'Confirm with serology and microscopy (urine/stool for ova; time samples appropriately after exposure)',
      'Treat with praziquantel (timed correctly — it is less effective against immature worms, so acute infection may need repeat dosing)',
      'Refer to infectious diseases / tropical medicine for diagnosis and treatment, particularly in acute or complicated disease',
      'Investigate and manage chronic complications (haematuria, obstructive uropathy, portal hypertension)',
      'Advise travellers on prevention: avoid freshwater contact in endemic areas',
      'Screen and treat returning groups with shared exposure (e.g. travel companions)',
      'Maintain awareness of the long-term bladder cancer risk in chronic urinary disease'],
    referral:[
      'Acute (Katayama) or complicated schistosomiasis → infectious diseases / tropical medicine',
      'Visible haematuria, or chronic urinary schistosomiasis → urology (long-term bladder squamous-cell carcinoma risk; investigate per haematuria/NICE NG12 bladder cancer pathway)',
      'Hepatosplenic disease/portal hypertension → hepatology/gastroenterology',
      'Neurological schistosomiasis (rare: transverse myelitis) → emergency neurology'],
    source:'NICE CKS / UKHSA / tropical medicine guidance' },

  { id:'binge-eating', title:'Binge eating disorder (BED)', category:'Mental health', icon:'🍽️',
    overview:'Recurrent episodes of eating unusually large amounts of food with a sense of loss of control and marked distress, but without the regular compensatory behaviours of bulimia. It is the commonest eating disorder, frequently associated with obesity, and is under-recognised because of stigma.',
    features:[
      'Recurrent binge episodes: eating rapidly, to uncomfortable fullness, when not hungry, alone through embarrassment, with guilt/disgust afterwards',
      'No regular purging, fasting or excessive exercise (which would suggest bulimia)',
      'Marked distress about bingeing; eating often used to manage emotions',
      'Frequently coexists with obesity and its complications, and with depression, anxiety and low self-esteem',
      'Weight may be normal, overweight or obese — do not assume from appearance',
      'Distinguish from bulimia (compensatory behaviours) and from "comfort eating" that lacks loss of control and distress'],
    management:[
      'Ask sensitively and non-judgementally; screen where there is obesity, weight fluctuation or mood disorder',
      'Assess severity, physical health (BMI, metabolic complications), mood and risk',
      'First-line treatment is a structured, BED-focused guided self-help programme based on cognitive behavioural principles (NICE NG69)',
      'If guided self-help is unsuitable/ineffective, offer group or individual CBT for eating disorders (CBT-ED)',
      'Address the disordered eating before focusing on weight loss; weight-management programmes alone do not treat BED',
      'Treat comorbid depression/anxiety; an SSRI may help mood and can reduce binge frequency, but is an adjunct to psychological therapy',
      'Manage physical health consequences (weight, glycaemia, lipids, blood pressure) supportively and without stigma',
      'Provide information and signpost eating-disorder support; review progress regularly'],
    referral:[
      'Moderate–severe, complex, or treatment-resistant BED → community eating-disorder service',
      'Significant psychiatric comorbidity or risk → mental-health services',
      'Children and young people → CAMHS / specialist eating-disorder service',
      'Significant physical complications of obesity → relevant medical/weight-management pathways'],
    source:'NICE NG69 (Eating disorders)' },

  { id:'bird-flu', title:'Bird flu (avian influenza)', category:'Infectious diseases', icon:'🦠',
    overview:'Influenza A viruses (notably H5N1, H7N9) that primarily infect birds but can occasionally infect humans, usually after close contact with infected poultry. Human cases are rare but can cause severe respiratory illness with high mortality, and there is ongoing pandemic-preparedness concern. Suspicion rests on exposure plus a compatible illness.',
    features:[
      'Exposure history is key: contact with sick/dead poultry or wild birds, poultry markets, or travel to an area with known outbreaks',
      'Illness ranges from mild (conjunctivitis, mild flu-like symptoms) to severe influenza with high fever, cough and rapidly progressive pneumonia',
      'Severe cases progress to respiratory failure/ARDS and multi-organ dysfunction',
      'Incubation is usually within about 7–10 days of exposure',
      'Differentials: seasonal influenza, COVID-19, other viral/bacterial pneumonia',
      'Human-to-human transmission is currently very limited — but is the feared scenario for a pandemic'],
    management:[
      'Maintain a travel/exposure history in anyone with an influenza-like illness and recent bird contact or relevant travel',
      'If avian influenza is suspected, contact the local health protection team (UKHSA) urgently — this is a notifiable concern',
      'Isolate the patient and use appropriate infection-control precautions to protect staff and contacts',
      'Antiviral treatment (neuraminidase inhibitors, e.g. oseltamivir) early; severe cases need hospital admission and supportive critical care',
      'Antiviral post-exposure prophylaxis may be advised for close contacts under public-health guidance',
      'Do not delay public-health notification for confirmatory testing if suspicion is high',
      'Follow current UKHSA case definitions and pathways, which change as the epidemiology evolves',
      'Provide general advice on avoiding contact with sick/dead birds'],
    referral:[
      'Suspected human avian influenza → urgent discussion with UKHSA / health protection team and hospital infectious diseases',
      'Severe respiratory illness or hypoxia → emergency admission for supportive/critical care',
      'Close contacts → public-health-led monitoring ± antiviral prophylaxis',
      'Notify per statutory public-health requirements'],
    source:'UKHSA avian influenza guidance' },

  { id:'birthmarks', title:'Birthmarks', category:'Dermatology', icon:'🍓',
    overview:'Coloured skin marks present at or shortly after birth, divided into vascular (e.g. infantile haemangioma, port-wine stain, salmon patch) and pigmented (e.g. congenital melanocytic naevus, café-au-lait, Mongolian spot). Most are harmless, but a few signal underlying syndromes or need timely treatment to prevent complications.',
    features:[
      'Salmon patch ("stork mark"): flat pink patches on eyelids/nape — extremely common and usually fade',
      'Infantile haemangioma ("strawberry mark"): appears in first weeks, grows then involutes; problematic if near the eye/airway, ulcerated, or multiple',
      'Port-wine stain (capillary malformation): a flat red/purple patch that persists and darkens; facial (trigeminal) distribution may suggest Sturge-Weber syndrome',
      'Congenital melanocytic naevus: a pigmented mole; large/giant lesions carry a small melanoma risk and possible neurocutaneous involvement',
      'Café-au-lait macules: ≥6 (>5 mm pre-pubertal / >15 mm post-pubertal) suggest neurofibromatosis type 1',
      'Mongolian spot/dermal melanocytosis: blue-grey sacral patches in darker skin — benign but document to avoid confusion with bruising/safeguarding concern'],
    management:[
      'Identify the type; most (salmon patches, small haemangiomas, Mongolian spots) need only reassurance and explanation of natural history',
      'Document Mongolian spots clearly to prevent mistaken non-accidental-injury concerns',
      'Refer high-risk infantile haemangiomas early (peri-ocular, airway/"beard" distribution, nasal tip, ulcerated, large/segmental, or multiple) — oral propranolol is highly effective but must be started during the proliferative phase',
      'Refer port-wine stains for assessment (pulsed-dye laser; ophthalmology/neurology if Sturge-Weber suspected for facial lesions involving the eyelid)',
      'Assess large/giant congenital naevi for melanoma and neurocutaneous risk; arrange dermatology follow-up',
      'Count and measure café-au-lait macules and assess for other NF1 features; refer if criteria are met',
      'Provide written information and clear safety-netting on changes',
      'Support families regarding cosmetic and psychological impact'],
    referral:[
      'High-risk infantile haemangioma → urgent dermatology/paediatrics (timely propranolol)',
      'Port-wine stain, especially facial/peri-ocular (?Sturge-Weber) → dermatology ± ophthalmology/neurology',
      'Large/giant congenital melanocytic naevus, or any changing/atypical pigmented lesion → dermatology (melanoma surveillance; NICE NG12 for suspicious lesions)',
      '≥6 café-au-lait macules or other NF1 features → paediatrics/genetics'],
    source:'NICE CKS / BAD guidance' },

  { id:'bite-animal-human', title:'Bite (animal or human)', category:'General', icon:'🦷',
    overview:'Mammalian bites (dog, cat, human) carry a significant infection risk and, depending on context, rabies and tetanus considerations. Human bites and cat bites are especially prone to infection. Management centres on wound care, risk-assessed antibiotics, and tetanus/rabies/blood-borne-virus assessment.',
    features:[
      'Dog bites: often crush/laceration injuries with tissue damage; lower infection rate than cat/human but can be severe',
      'Cat bites: deep puncture wounds that inoculate bacteria deeply — high infection risk (Pasteurella multocida)',
      'Human bites: high infection risk and polymicrobial; "clenched-fist" injuries over the knuckles (a fight bite) can penetrate the joint — treat seriously',
      'Signs of infection: increasing pain, spreading erythema, swelling, discharge, lymphangitis, fever (may develop rapidly with Pasteurella)',
      'Assess depth, involvement of joints/tendons/bones/nerves, and the wound site (hands, face, genitalia are higher risk)',
      'Consider rabies risk (bites abroad/bats), tetanus status, and blood-borne viruses (human bites breaking skin)'],
    management:[
      'Thorough irrigation and cleansing of the wound is the single most important step; remove foreign material and debride devitalised tissue as appropriate',
      'Generally do not primarily close bite wounds (especially puncture/hand/cat/human bites) — leave open or delayed closure to reduce infection; facial wounds may be an exception with specialist input',
      'Offer prophylactic antibiotics (co-amoxiclav first-line) for higher-risk bites: cat bites, human bites, hands/feet/face/genital sites, deep/puncture wounds, immunocompromised/diabetic patients, or where there is delay/devitalised tissue',
      'Treat established infection with antibiotics; review and have a low threshold for escalation',
      'Check and update tetanus immunisation per status and wound risk; give tetanus immunoglobulin if indicated',
      'Risk-assess rabies (bites abroad, bat exposure) and discuss urgently with health protection for post-exposure prophylaxis',
      'For human bites breaking skin, assess blood-borne-virus risk (hepatitis B/C, HIV) and consider PEP/vaccination',
      'Safety-net clearly for spreading infection and arrange follow-up'],
    referral:[
      'Clenched-fist/"fight bite" over a knuckle, or any joint/tendon/bone involvement → urgent hand surgery / orthopaedics (risk of septic arthritis)',
      'Severe, deep, or extensively infected wounds, or systemic sepsis → emergency surgical assessment',
      'Possible rabies exposure (abroad/bats) → urgent discussion with UKHSA/health protection for PEP',
      'Significant facial wounds or cosmetic concern → plastic surgery / maxillofacial'],
    source:'NICE NG184 (Bites — human and animal) / Green Book (tetanus, rabies)' },

  { id:'black-eye', title:'Black eye (periorbital haematoma)', category:'General', icon:'🥊',
    overview:'Bruising around the eye after blunt trauma. Usually minor, but it can accompany serious injury — to the globe itself, the orbit (blow-out fracture), or the head (base-of-skull fracture). The task is to identify the eye and head injuries that need urgent care, and to consider non-accidental injury.',
    features:[
      'Periorbital swelling and bruising after trauma; the eyelid may swell shut',
      'RED FLAGS for eye injury: reduced visual acuity, diplopia, an irregular/non-reactive pupil, hyphaema (blood in the anterior chamber), or severe eye pain',
      'Orbital blow-out fracture clues: restricted/painful eye movement (especially upgaze), vertical diplopia, infraorbital numbness, and enophthalmos',
      'Base-of-skull fracture clues: bilateral "panda/raccoon eyes" without direct trauma, CSF rhinorrhoea/otorrhoea, Battle’s sign (mastoid bruising)',
      'Consider the head-injury assessment if there was significant force, loss of consciousness, or other neurology',
      'Always consider non-accidental injury in children and vulnerable adults — especially if the history is inconsistent or there are other injuries'],
    management:[
      'Assess visual acuity, pupils, eye movements and the globe; examine for facial-bone and head-injury features',
      'Uncomplicated isolated periorbital bruising: reassure, cold compresses, simple analgesia; bruising resolves over 1–2 weeks',
      'Examine the eye carefully — if you cannot exclude globe/orbital injury, refer',
      'Apply the head-injury (NICE NG232) criteria if there is any suggestion of significant head trauma',
      'Advise on safety-netting: seek urgent review for visual change, double vision, increasing pain, or neurological symptoms',
      'Document the injury and mechanism carefully',
      'Be alert to safeguarding — assault, domestic abuse, and child/vulnerable-adult protection',
      'Check tetanus status if there is an associated wound'],
    referral:[
      'Any sign of globe injury (reduced acuity, hyphaema, abnormal pupil, severe pain, penetrating injury) → same-day ophthalmology',
      'Suspected orbital blow-out fracture (diplopia, restricted gaze, infraorbital numbness, enophthalmos) → maxillofacial/ophthalmology',
      'Features of base-of-skull/significant head injury → emergency department (NICE NG232)',
      'Safeguarding concern → follow local child/adult protection procedures'],
    source:'NICE NG232 (Head injury) / NICE CKS' },

  { id:'boils', title:'Boils and carbuncles (furuncles)', category:'Dermatology', icon:'🔴',
    overview:'A boil (furuncle) is a deep bacterial infection of a hair follicle, usually Staphylococcus aureus; a carbuncle is a coalescence of several into a larger, deeper lesion. Most are self-limiting or settle with simple measures; recurrent or severe disease prompts a search for predisposing factors and PVL-Staph.',
    features:[
      'A painful, red, firm nodule that becomes fluctuant and points, then discharges pus',
      'Common at friction/sweat sites: neck, axillae, buttocks, thighs, face',
      'A carbuncle is larger, with multiple draining sinuses, often with systemic upset',
      'Predisposing factors: diabetes, obesity, immunosuppression, skin disease, poor hygiene, and nasal/skin S. aureus carriage',
      'Recurrent boils, multiple family members affected, or unusually severe abscesses suggest Panton-Valentine leukocidin (PVL) Staphylococcus aureus',
      'Differential: hidradenitis suppurativa (recurrent flexural abscesses/sinuses), epidermoid cyst, cystic acne'],
    management:[
      'Most single boils need only warm compresses to encourage drainage and simple analgesia',
      'Incision and drainage is the definitive treatment once a boil/abscess is fluctuant',
      'Antibiotics are not routinely needed for a simple drained boil; reserve them for surrounding cellulitis, systemic illness, facial lesions ("danger triangle"), immunosuppression, or multiple/large lesions',
      'Send pus for culture in significant, recurrent, or treatment-failing infections (and to detect MRSA/PVL-SA)',
      'For recurrent disease: assess for diabetes and other risk factors, and consider decolonisation (e.g. nasal mupirocin and antiseptic body wash) — for the patient and sometimes household contacts',
      'Hygiene advice: handwashing, not sharing towels/razors, and covering draining lesions',
      'Suspect and investigate PVL-SA where there are recurrent/severe abscesses or household clustering, and follow local microbiology guidance',
      'Consider and exclude hidradenitis suppurativa where flexural abscesses recur'],
    referral:[
      'Facial boils with significant cellulitis or systemic illness → consider urgent assessment (cavernous sinus risk from the "danger triangle")',
      'Large carbuncle, severe/spreading infection, or sepsis → surgical/medical admission',
      'Recurrent PVL-Staph or treatment-resistant disease → microbiology/dermatology advice',
      'Recurrent flexural abscesses with sinuses/scarring → dermatology (hidradenitis suppurativa)'],
    source:'NICE CKS — Boils, carbuncles and staphylococcal carriage' },

  { id:'bpd', title:'Borderline (emotionally unstable) personality disorder', category:'Mental health', icon:'🧠',
    overview:'A personality disorder characterised by pervasive instability of emotions, self-image and relationships with marked impulsivity, beginning by early adulthood. Self-harm and suicide risk are high. Care is built on a consistent, validating therapeutic relationship and structured psychological therapy — not medication.',
    features:[
      'Intense, unstable relationships alternating between idealisation and devaluation',
      'Emotional instability with rapid mood shifts, chronic emptiness, and intense, poorly controlled anger',
      'Impulsivity (spending, substances, sex, binge eating) and recurrent self-harm or suicidal behaviour',
      'Frantic efforts to avoid abandonment; unstable self-image; transient stress-related paranoia or dissociation',
      'Strong association with trauma (childhood abuse/neglect) and high comorbidity (depression, PTSD, substance misuse, eating disorders)',
      'Distinguish from bipolar disorder (sustained episodes vs rapid reactive shifts) and from comorbid mood/psychotic disorders'],
    management:[
      'Build a consistent, reliable, non-judgemental therapeutic relationship with clear, agreed boundaries — continuity matters more than any single intervention',
      'Validate distress; manage crises collaboratively and develop a written crisis/safety plan with the patient',
      'Refer for structured, evidence-based psychological therapy (e.g. dialectical behaviour therapy, mentalisation-based therapy) — the mainstay of treatment',
      'Do not use medication to treat the disorder itself (NICE CG78); treat genuine comorbid conditions (e.g. depression, PTSD) on their own merits and review/avoid polypharmacy',
      'Assess and manage risk at every contact without over-reacting; chronic risk needs a planned, consistent approach rather than repeated crisis escalation',
      'Be cautious with hypnotics/sedatives and quantities prescribed given overdose risk',
      'Treat comorbid substance misuse and physical health needs',
      'Support continuity, involve community mental-health teams for moderate–severe disease, and look after the clinical team’s own consistency'],
    referral:[
      'Moderate–severe disorder, or where structured psychological therapy is needed → community mental-health team / specialist personality-disorder service',
      'Acute suicidality or significant escalation in risk → crisis/home-treatment team',
      'Significant comorbidity (e.g. eating disorder, PTSD, substance misuse) → relevant specialist services',
      'Young people with emerging features → CAMHS'],
    source:'NICE CG78 (Borderline personality disorder)' },

  { id:'bowel-polyps', title:'Bowel polyps', category:'Gastroenterology', icon:'🧫',
    overview:'Growths projecting from the colonic mucosa. Most are benign, but adenomatous (and serrated) polyps are precursors to colorectal cancer through the adenoma-carcinoma sequence — which is why detection and removal, plus surveillance, prevent cancer. Most are asymptomatic and found at colonoscopy or screening.',
    features:[
      'Usually asymptomatic; larger polyps may cause rectal bleeding, a change in bowel habit, or mucus',
      'Histology matters: adenomatous and serrated polyps are pre-malignant; hyperplastic polyps are generally low-risk',
      'Detected through the NHS Bowel Cancer Screening Programme (FIT-based, then colonoscopy) or during investigation of symptoms',
      'Polyposis syndromes (e.g. familial adenomatous polyposis, Lynch syndrome, Peutz-Jeghers) cause numerous polyps and very high cancer risk — suspect with a strong family history or young onset',
      'Risk factors mirror colorectal cancer: age, family history, obesity, smoking, alcohol, low-fibre diet, IBD',
      'Diagnosis and removal are by colonoscopy (polypectomy) with histological assessment'],
    management:[
      'Investigate symptoms suggestive of colorectal pathology with FIT and refer appropriately — do not dismiss a change in bowel habit or rectal bleeding',
      'Polyps are removed at colonoscopy (polypectomy) and sent for histology',
      'Surveillance colonoscopy intervals are set by the number, size and histology of polyps found (per BSG/specialist guidance)',
      'Encourage uptake of the national bowel-cancer screening programme in eligible patients',
      'Support risk reduction: stop smoking, reduce alcohol, healthy weight, and a high-fibre diet',
      'Identify possible hereditary polyposis/Lynch syndrome (young onset, multiple polyps, strong family history) and refer for genetics',
      'Ensure patients understand and attend their surveillance colonoscopies',
      'Safety-net for new symptoms between surveillance episodes'],
    referral:[
      'Colorectal symptoms meeting NICE NG12 thresholds → 2WW colorectal pathway: e.g. ≥40 with abdominal pain + weight loss; ≥50 with unexplained rectal bleeding; ≥60 with iron-deficiency anaemia or change in bowel habit; use FIT (≥10 µg Hb/g) to guide urgent referral in symptomatic patients',
      'Polyps found → colonoscopic polypectomy and histology, then risk-based surveillance',
      'Suspected hereditary polyposis / Lynch syndrome → clinical genetics + specialist surveillance',
      'Positive screening FIT → colonoscopy via the screening programme'],
    source:'NICE NG12 / BSG polyp surveillance guidance' },

  { id:'bowens-disease', title:'Bowen’s disease (squamous cell carcinoma in situ)', category:'Dermatology', icon:'🩹',
    overview:'An intra-epidermal (in-situ) squamous cell carcinoma presenting as a slow-growing, scaly erythematous patch. It is generally indolent, but a small proportion progress to invasive SCC — so the priorities are correct diagnosis, treatment, and recognising features of invasion.',
    features:[
      'A well-demarcated, slowly enlarging, erythematous scaly or crusted plaque, often on sun-exposed sites (lower legs in older women, head/neck)',
      'Usually asymptomatic; may itch, crust or bleed',
      'Risk factors: chronic sun exposure, fair skin, older age, immunosuppression, HPV (genital/digital lesions), and prior radiotherapy/arsenic exposure',
      'Differential: psoriasis, eczema, superficial BCC, actinic keratosis, and invasive SCC',
      'RED FLAGS for progression to invasive SCC: a developing nodule, induration, ulceration, bleeding, pain, or rapid growth',
      'Diagnosis is confirmed by biopsy where there is any doubt'],
    management:[
      'Confirm the diagnosis — biopsy if uncertain or if invasion is suspected',
      'Treatment options (lesion- and patient-dependent): topical 5-fluorouracil or imiquimod, cryotherapy, curettage and cautery, photodynamic therapy, or excision',
      'Lower-leg lesions in older patients heal slowly — choose treatments mindful of wound healing',
      'Advise sun protection and skin self-surveillance; manage other actinic damage',
      'Review treated lesions to confirm clearance and watch for recurrence',
      'Have a low threshold for biopsy/referral if a treated or new lesion becomes nodular, indurated or ulcerated',
      'In immunosuppressed patients (e.g. transplant recipients) maintain closer surveillance — higher progression risk',
      'Provide patient information on the condition and its low but real malignant potential'],
    referral:[
      'Suspected invasive SCC (nodule, induration, ulceration, rapid growth, bleeding) → 2WW suspected skin-cancer referral (NICE NG12)',
      'Diagnostic uncertainty or lesions unsuitable for primary-care treatment → dermatology',
      'Immunosuppressed patients with Bowen’s disease → dermatology for surveillance',
      'Treatment failure or recurrence → dermatology'],
    source:'NICE NG12 / BAD Bowen’s disease guidance' },

  { id:'plagiocephaly', title:'Brachycephaly and plagiocephaly (flat head)', category:'Paediatrics', icon:'👶',
    overview:'Positional skull deformities in infants — flattening at the back (brachycephaly) or one side (plagiocephaly) — caused by external moulding, strongly linked to back-sleeping (rightly recommended for SIDS prevention). They are benign and usually improve, but must be distinguished from craniosynostosis.',
    features:[
      'Positional plagiocephaly: unilateral occipital flattening with the ear pushed forward on the same side, producing a parallelogram-shaped head when viewed from above',
      'Brachycephaly: symmetrical flattening across the back of the head with a broad, short skull',
      'Develops/worsens in the first months and is associated with back-sleeping, prematurity, reduced tummy time, and neck tightness (torticollis)',
      'Reassuringly, the open fontanelle and sutures are normal and head growth is normal',
      'CRANIOSYNOSTOSIS (the key differential) is suggested by a ridged/fused suture, an abnormal head shape that worsens, a small/closing fontanelle, or restricted skull growth',
      'Examine the neck for congenital muscular torticollis, which both causes and is caused by positional preference'],
    management:[
      'Reassure: positional plagiocephaly/brachycephaly is benign, does not affect brain development, and usually improves as the baby becomes more mobile',
      'Advise repositioning: alternate head position during sleep (while still placing the baby on their back), encourage supervised "tummy time" when awake, and limit time in car seats/bouncers',
      'Continue to recommend back-sleeping for SIDS prevention — do not advise prone sleeping',
      'Treat any associated torticollis with neck-stretching exercises and physiotherapy referral if needed',
      'Most improve by 12–18 months; helmet/orthotic therapy is not routinely recommended (limited evidence, costly)',
      'Examine the skull sutures and fontanelle to exclude craniosynostosis',
      'Provide written information and review to confirm improvement',
      'Reassess if the head shape worsens or fails to improve with repositioning'],
    referral:[
      'Suspected craniosynostosis (palpable suture ridge, abnormal/worsening shape, restricted skull growth) → paediatrics / craniofacial service',
      'Persistent/severe positional deformity not improving, or significant torticollis → paediatrics/physiotherapy',
      'Parental concern or diagnostic uncertainty → paediatric assessment',
      'Any sign of raised intracranial pressure or developmental concern → urgent paediatrics'],
    source:'NICE CKS — Plagiocephaly and brachycephaly' },

  { id:'breath-holding', title:'Breath-holding spells in babies and children', category:'Paediatrics', icon:'👶',
    overview:'Involuntary, reflexive episodes in young children (usually 6 months–5 years) triggered by upset, pain or frustration, in which the child stops breathing, may change colour, and may briefly lose consciousness. They are benign and self-limiting but frightening for parents; iron deficiency is a treatable contributor.',
    features:[
      'Cyanotic type (commonest): triggered by crying/frustration — the child cries, holds their breath in expiration, turns blue, and may go limp or briefly lose consciousness',
      'Pallid type: triggered by sudden pain/fright (a vasovagal mechanism) — the child goes pale and limp, with brief loss of consciousness',
      'Episodes are brief, with rapid spontaneous recovery; occasionally a few clonic jerks occur (anoxic, not epileptic)',
      'Always provoked by a trigger and preceded by crying/upset — a key distinction from epileptic seizures (which are typically unprovoked)',
      'Peak 6 months–5 years; usually resolve by school age; a family history is common',
      'Associated with iron-deficiency anaemia, which can increase frequency'],
    management:[
      'Confirm the diagnosis from a clear history of a trigger and the typical sequence; examine the cardiovascular and neurological systems',
      'Reassure strongly: spells are benign, do not cause brain damage, and the child outgrows them',
      'Advise parents on first aid: stay calm, keep the child safe and lying down during an episode, do not shake or splash water, and avoid reinforcing the behaviour afterwards',
      'Check ferritin/FBC — treat iron deficiency, as iron supplementation reduces spell frequency',
      'Help parents manage triggers and tantrums consistently without giving in to avoid spells',
      'Safety-net: seek review for atypical features, prolonged episodes, or episodes without a trigger',
      'Consider an ECG if pallid spells are frequent/atypical, to exclude a cardiac arrhythmia (e.g. long QT)',
      'Provide written information and follow-up reassurance'],
    referral:[
      'Atypical features, episodes without a clear trigger, prolonged loss of consciousness, or focal neurology → paediatrics (exclude epilepsy/cardiac cause)',
      'Frequent pallid spells or family history of sudden cardiac death/arrhythmia → paediatric cardiology (ECG, ?long QT)',
      'Diagnostic uncertainty → paediatric assessment',
      'Refractory iron deficiency → investigate per cause'],
    source:'NICE CKS — Breath-holding spells' },

  { id:'fracture', title:'Broken bone (fracture)', category:'Musculoskeletal', icon:'🦴',
    overview:'A break in the continuity of bone, from a hairline crack to a displaced or open injury. Most follow trauma; the primary-care tasks are recognising fractures, identifying those needing emergency care, arranging imaging, and — importantly — considering pathological and fragility fractures and non-accidental injury.',
    features:[
      'Pain, swelling, bruising, deformity, reduced function and localised bony tenderness after trauma',
      'Specific clinical decision rules help (e.g. Ottawa ankle/knee rules) to target X-rays appropriately',
      'OPEN fracture (skin breached over the break) and neurovascular compromise are emergencies',
      'Fragility fracture: a fracture from a fall from standing height or less — a marker of osteoporosis needing bone-health assessment (and, in the over-50s, FRAX/DXA)',
      'PATHOLOGICAL fracture: a break through abnormal bone (metastasis, myeloma, primary tumour) — suspect with minimal trauma, preceding bone pain, or a known cancer',
      'Always consider non-accidental injury in children (especially unexplained fractures, inconsistent history, or certain patterns) and vulnerable adults'],
    management:[
      'Assess pain, deformity, skin integrity, and distal neurovascular status; provide analgesia and immobilise/splint',
      'Apply clinical decision rules to decide on X-ray; arrange imaging for suspected fracture',
      'Refer acute, displaced, open, or neurovascularly compromised fractures urgently to the emergency department/orthopaedics',
      'Undisplaced stable fractures may be managed with immobilisation and follow-up per local pathways (e.g. virtual fracture clinics)',
      'After a fragility fracture, assess and manage bone health (lifestyle, calcium/vitamin D, FRAX ± DXA, and bone-protection treatment where indicated)',
      'Investigate suspected pathological fracture (bloods including calcium/myeloma screen, imaging) and refer on the relevant cancer pathway',
      'Update tetanus and give antibiotics for open fractures while arranging urgent surgical care',
      'Address safeguarding where the history or pattern is concerning, and arrange rehabilitation/physiotherapy'],
    referral:[
      'Open fracture, gross deformity, dislocation, or neurovascular compromise → emergency orthopaedics/ED',
      'Suspected pathological fracture (minimal trauma, preceding bone pain, known/possible malignancy) → urgent investigation; suspected myeloma → very urgent protein electrophoresis/BJP and FBC, suspected bone metastasis/sarcoma → relevant 2WW pathway (NICE NG12)',
      'Fragility fracture → fracture-liaison/bone-health assessment for osteoporosis management',
      'Suspected non-accidental injury → follow safeguarding procedures'],
    source:'NICE CKS / NICE NG38 (fractures) / NICE NG12' },

  { id:'bronchiolitis', title:'Bronchiolitis', category:'Paediatrics', icon:'🫁',
    overview:'A common lower-respiratory-tract viral infection of infants (usually <1 year, peak 3–6 months), most often RSV, causing inflammation of the small airways. Most is mild and self-limiting, but a minority — especially young or high-risk infants — develop respiratory distress or feeding failure needing admission.',
    features:[
      'Coryzal prodrome for 1–3 days, then cough, tachypnoea, wheeze and/or fine bibasal crackles',
      'Feeding difficulty due to respiratory effort and nasal congestion; reduced wet nappies',
      'Peak severity around days 3–5; cough may persist up to 3 weeks',
      'Signs of increasing respiratory distress: nasal flaring, grunting, intercostal/subcostal recession, tachypnoea, and tracheal tug',
      'RED FLAGS for admission: apnoea, marked respiratory distress, persistent oxygen saturation <90–92%, poor feeding (<50–75% of normal), dehydration, or exhaustion',
      'Higher risk: age <3 months, prematurity, chronic lung/heart disease, neuromuscular disorders, and immunodeficiency'],
    management:[
      'Diagnose clinically; routine investigations (CXR, bloods) are not needed in typical cases',
      'Most infants are managed at home with supportive care: small frequent feeds, adequate fluids, paracetamol for distress from fever, and saline nasal drops for congestion',
      'Do NOT use antibiotics, bronchodilators (salbutamol), steroids, nebulised adrenaline or nebulised hypertonic saline — none are effective in bronchiolitis',
      'Give clear safety-netting on the red flags for deterioration and how to seek help, and advise on the expected course',
      'Admit infants with the red-flag features above for oxygen, feeding support (NG/IV fluids) and monitoring',
      'Consider lower thresholds for admission/review in young or high-risk infants and where social circumstances make safety-netting unreliable',
      'Advise smoke-free environments and good hand hygiene to reduce spread',
      'Mention palivizumab prophylaxis for eligible high-risk infants (specialist-led)'],
    referral:[
      'Apnoea, severe respiratory distress, saturations persistently <90–92%, inadequate feeding/dehydration, or exhaustion → emergency hospital admission',
      'Clinician uncertainty, young/high-risk infant, or unreliable home circumstances → lower threshold for admission/paediatric assessment',
      'Diagnostic doubt (e.g. possible pneumonia, heart failure, foreign body) → paediatric assessment',
      'High-risk infants for RSV prophylaxis → specialist paediatrics'],
    source:'NICE NG9 (Bronchiolitis in children)' },

  { id:'acute-bronchitis', title:'Acute bronchitis', category:'Respiratory', icon:'🫁',
    overview:'Self-limiting inflammation of the large airways, usually viral, causing an acute cough (often productive) in an otherwise well person. The clinical skills are distinguishing it from pneumonia, resisting unnecessary antibiotics, and recognising the cough that needs a chest X-ray for possible cancer.',
    features:[
      'Acute cough (the dominant symptom), often productive of clear/discoloured sputum, frequently with a preceding coryzal illness',
      'May have wheeze, chest discomfort and mild breathlessness; cough can persist for up to 3 weeks',
      'Usually no significant systemic upset and a clear chest, or scattered wheeze/coarse crackles that change with coughing',
      'PNEUMONIA is suggested by focal chest signs, high fever, tachypnoea, tachycardia, hypoxia and feeling very unwell — assess with CRB-65 and examine carefully',
      'Sputum colour alone does not indicate a bacterial cause or the need for antibiotics',
      'A cough persisting >3 weeks, or with haemoptysis/weight loss, warrants a chest X-ray (lung cancer consideration)'],
    management:[
      'Distinguish from pneumonia clinically; most acute bronchitis needs no antibiotics (NICE NG120)',
      'Self-care: rest, fluids, paracetamol/ibuprofen for fever/discomfort; honey or over-the-counter cough remedies may give modest symptom relief',
      'Give clear advice on the natural history (cough up to 3 weeks) and safety-netting for deterioration',
      'Consider a back-up/delayed antibiotic prescription only where there is concern about deterioration or higher risk (frail, comorbid)',
      'Treat antibiotics promptly if pneumonia is suspected or the patient is systemically unwell/high-risk',
      'Use a CRB-65 assessment when pneumonia is a possibility to guide management and admission',
      'Arrange a chest X-ray for a cough lasting >3 weeks, or with red-flag features, to exclude lung cancer and other pathology',
      'Reinforce smoking cessation and review patients who fail to improve'],
    referral:[
      'Suspected pneumonia with high CRB-65 or systemic compromise → admission',
      'Cough ≥3 weeks (unexplained), especially with haemoptysis, weight loss, or in a smoker/ex-smoker aged ≥40 → urgent chest X-ray and 2WW suspected lung-cancer pathway if indicated (NICE NG12)',
      'Recurrent episodes or underlying chronic lung disease → respiratory review',
      'Failure to improve or diagnostic uncertainty → reassess and image'],
    source:'NICE NG120 (Cough — antimicrobial prescribing) / NICE NG12' },

  { id:'brucellosis', title:'Brucellosis', category:'Infectious diseases', icon:'🦠',
    overview:'A zoonotic bacterial infection (Brucella species) acquired from infected livestock — via unpasteurised dairy, direct animal contact, or occupational exposure. Rare in the UK and usually imported, it causes a non-specific febrile illness ("undulant fever") and is a classic cause of pyrexia of unknown origin in returning travellers.',
    features:[
      'Insidious onset of fever (classically undulant — rising and falling), drenching night sweats, malaise, fatigue, myalgia and weight loss',
      'Exposure history: consumption of unpasteurised milk/cheese, contact with cattle/sheep/goats, or work as a farmer/vet/abattoir worker, often abroad (Mediterranean, Middle East, Central Asia)',
      'Focal complications: sacroiliitis/arthritis, spondylitis, epididymo-orchitis, hepatosplenomegaly, and (serious) endocarditis or neurobrucellosis',
      'A characteristic foul/peculiar body odour is sometimes described',
      'Differentials: other causes of PUO/returning-traveller fever — TB, typhoid, malaria, lymphoma, endocarditis',
      'Diagnosis: blood (and bone-marrow) cultures (warn the lab — slow-growing and a laboratory hazard) and serology'],
    management:[
      'Take a careful exposure and travel history in anyone with prolonged unexplained fever',
      'Discuss with and refer to infectious diseases for diagnosis and treatment',
      'Treatment requires prolonged combination antibiotics (e.g. doxycycline plus rifampicin, or doxycycline plus an aminoglycoside) for ≥6 weeks to prevent relapse',
      'Alert the laboratory when requesting cultures — Brucella is a recognised laboratory-acquired infection hazard',
      'Investigate and treat focal complications (e.g. echocardiography for endocarditis, imaging for spondylitis)',
      'Brucellosis is a notifiable disease — inform the health protection team',
      'Advise on prevention: avoid unpasteurised dairy and use protective measures with occupational animal exposure',
      'Arrange follow-up to confirm response and detect relapse'],
    referral:[
      'Suspected/confirmed brucellosis → infectious diseases for combination antibiotic therapy',
      'Suspected endocarditis or neurobrucellosis → urgent specialist (cardiology/neurology) assessment',
      'Severe systemic illness → hospital admission',
      'Notify public health (statutorily notifiable)'],
    source:'UKHSA / NICE CKS — Fever in returning travellers' },

  { id:'brugada', title:'Brugada syndrome', category:'Cardiovascular & Renal', icon:'🫀',
    overview:'An inherited (usually autosomal-dominant, often SCN5A) cardiac sodium-channelopathy causing a characteristic ECG pattern and a risk of polymorphic ventricular arrhythmia and sudden cardiac death in a structurally normal heart. It is an important cause of sudden death in young (often male) adults, frequently during sleep or fever.',
    features:[
      'Often asymptomatic and detected on an incidental ECG; may present with syncope, nocturnal agonal breathing, palpitations, or aborted sudden cardiac death',
      'Type 1 ("coved") Brugada ECG pattern: ≥2 mm coved ST elevation followed by a negative T wave in the right precordial leads (V1–V2)',
      'Arrhythmia and death are often precipitated by fever, large meals, alcohol, vagal tone (sleep), and certain drugs',
      'A strong family history of sudden cardiac death (especially young or nocturnal) is a major clue',
      'Predominantly affects men, often presenting in the third to fourth decade; commoner in South-East Asian populations',
      'Many drugs can unmask or worsen the pattern (e.g. certain antiarrhythmics, tricyclics, some psychotropics) — check brugadadrugs.org'],
    management:[
      'Recognise the type 1 Brugada ECG and refer to cardiology/inherited-cardiac-conditions service — do not dismiss as benign',
      'Treat fever promptly and aggressively with antipyretics (paracetamol) — fever is a key trigger for arrhythmia',
      'Avoid drugs known to provoke Brugada arrhythmias; check an up-to-date list before prescribing and review existing medications',
      'Risk stratification is specialist (symptoms, spontaneous type 1 pattern, electrophysiology); an implantable cardioverter-defibrillator (ICD) is the main protective treatment for high-risk patients',
      'Advise on lifestyle triggers: moderate alcohol, avoid large heavy meals if relevant, and seek care for fever',
      'Offer family screening (ECG ± genetic testing) and genetic counselling — it is heritable',
      'Provide clear advice on seeking urgent help for syncope or palpitations',
      'Document and flag the diagnosis prominently to avoid inadvertent prescribing of provoking drugs'],
    referral:[
      'Type 1 Brugada ECG, syncope of suspected cardiac cause, or family history of sudden cardiac death → cardiology / inherited-cardiac-conditions service',
      'Aborted cardiac arrest or sustained ventricular arrhythmia → emergency admission',
      'First-degree relatives of an affected patient → cardiac genetic screening',
      'Need for ICD or arrhythmia management → electrophysiology'],
    source:'NICE CKS / inherited cardiac conditions guidance' }

  );
})();
